// ── Dashboard Metrics Aggregator ─────────────────────────────────
// Processes data from 3 sources: HubSpot, GA4, Stripe
// Returns a single clean metrics object for the dashboard

const items = $input.all();
const now = new Date();
const errors = [];

// ── 1. Extract HubSpot Pipeline Metrics ─────────────────────────
let open_deals = 0, pipeline_value = 0;
try {
  const hubspotData = items.find(i => i.json.results);
  if (hubspotData) {
    const deals = hubspotData.json.results || [];
    open_deals = deals.length;
    pipeline_value = deals.reduce((sum, d) => sum + parseFloat(d.properties?.amount || 0), 0);
  }
} catch (e) { errors.push({ source: 'hubspot', error: e.message }); }

// ── 2. Extract GA4 Metrics ───────────────────────────────────────
let sessions = 0, conversions = 0, bounce_rate = 0, new_users = 0;
try {
  const ga4Data = items.find(i => i.json.rows);
  if (ga4Data && ga4Data.json.rows?.length > 0) {
    const row = ga4Data.json.rows[0].metricValues;
    sessions     = parseInt(row[0]?.value || 0);
    conversions  = parseInt(row[1]?.value || 0);
    bounce_rate  = parseFloat(row[2]?.value || 0).toFixed(2);
    new_users    = parseInt(row[3]?.value || 0);
  }
} catch (e) { errors.push({ source: 'ga4', error: e.message }); }

// ── 3. Extract Revenue Metrics ───────────────────────────────────
let revenue_today = 0, transactions_today = 0;
try {
  const revenueData = items.find(i => i.json.data && Array.isArray(i.json.data));
  if (revenueData) {
    const charges = revenueData.json.data.filter(c => c.paid && !c.refunded);
    transactions_today = charges.length;
    revenue_today = charges.reduce((sum, c) => sum + (c.amount / 100), 0);
  }
} catch (e) { errors.push({ source: 'stripe', error: e.message }); }

return [{
  json: {
    // Timestamp
    last_updated:       now.toISOString(),
    last_updated_human: now.toLocaleString('en-GB', { timeZone: 'Europe/London' }),
    // HubSpot
    open_deals,
    pipeline_value:     pipeline_value.toFixed(2),
    // GA4
    sessions_today:     sessions,
    conversions_today:  conversions,
    bounce_rate_pct:    bounce_rate,
    new_users_today:    new_users,
    // Revenue
    revenue_today:      revenue_today.toFixed(2),
    transactions_today,
    // Health
    source_errors:      errors,
    has_errors:         errors.length > 0
  }
}];

